/* DMA 环形缓冲区 ADT 接口定义（信息隐藏） */

#define RING_BUF_SIZE   256  /* 必须是 2 的幂次 */
#define RING_BUF_MASK   (RING_BUF_SIZE - 1)

typedef struct {
    uint8_t buffer[RING_BUF_SIZE];
    volatile uint16_t read_idx;
    volatile uint16_t write_idx;
    volatile uint8_t  dma_active;
} RingBuffer_t;

static RingBuffer_t g_uart_ring;

/* 模块内部：DMA 传输完成回调 —— 只有这个函数能修改 write_idx */
static void DMA_UartRxCompleteCallback(void) {
    g_uart_ring.dma_active = 0;
}

/* 公共接口：读取 n 字节，返回实际读取的字节数 */
uint16_t RingBuffer_Peek(RingBuffer_t *rb, uint8_t *out, uint16_t n) {
    uint16_t available = rb->write_idx - rb->read_idx;
    if (available == 0) return 0;  /* 空 */
    uint16_t to_read = (n < available) ? n : available;
    for (uint16_t i = 0; i < to_read; i++) {
        out[i] = rb->buffer[(rb->read_idx + i) & RING_BUF_MASK];
    }
    rb->read_idx += to_read;
    return to_read;
}

/* 公共接口：获取可用字节数 —— 供上层判断是否继续读取 */
uint16_t RingBuffer_Available(RingBuffer_t *rb) {
    return rb->write_idx - rb->read_idx;
}

/*
 * UART DMA 双缓冲循环接收
 * 平台: STM32F407, UART2, DMA2_Channel6
 * 缓冲区: bufA[128] + bufB[128], DMA Circular 模式
 */
#define UART_DMA_BUF_SIZE   128
#define UART_DMA_BUF_TOTAL  (UART_DMA_BUF_SIZE * 2)

static uint8_t uartDmaBuf[UART_DMA_BUF_TOTAL];
static volatile uint16_t dmaProcessedA = 0;  /* bufA 已处理的字节数 */
static volatile uint16_t dmaProcessedB = 0;  /* bufB 已处理的字节数 */
static volatile uint8_t  bufA_available = 0;   /* bufA 是否有未处理数据 */
static volatile uint8_t  bufB_available = 0;   /* bufB 是否有未处理数据 */

/* 启动 DMA 循环接收 —— 在系统初始化时调用一次 */
void UartDmaRx_Start(void) {
    /* 启动 DMA，双缓冲模式，缓冲区起始地址为 uartDmaBuf */
    HAL_UART_Receive_DMA(&huart2, uartDmaBuf, UART_DMA_BUF_TOTAL);
    /* HAL 内部设置 DMA2_Channel6 的 CIRC=1, MODE=1（循环模式） */
    /* 同时使能 HT 和 TC 中断：HAL 调用 HAL_DMA_Start_IT() */
}

/* DMA 半传输中断回调 —— bufA 的后半段写完，bufB 开始写入 */
void HAL_UARTEx_RxEventCallback(UART_HandleTypeDef *huart, uint16_t Size) {
    /* Size 为总传输长度（256），在此不做处理 */
    /* 实际数据可用性由 HT/TC 回调分别通知 */
    (void)huart;
    (void)Size;
}

/* DMA 半传输回调 —— bufA 前 128 字节已就绪，DMA 开始写 bufB */
void HAL_DMA_HalfCpltCallback(DMA_HandleTypeDef *hdma) {
    if (hdma->Instance == DMA2_Channel6) {
        /* 关键顺序：先复制数据，再清标志 —— DMA 会立即开始下一轮 */
        uint16_t len = bufA_available ? UART_DMA_BUF_SIZE : 0;
        if (len > 0) {
            /* bufA 有新数据，复制到处理缓冲区 */
            ProcessUartFrame(uartDmaBuf, len);  /* 用户处理函数 */
            bufA_available = 0;  /* 标记已处理 */
        }
        bufB_available = 1;  /* bufB 即将有新数据 */
    }
}

/* DMA 传输完成回调 —— 全部 256 字节处理完毕 */
void HAL_DMA_CpltCallback(DMA_HandleTypeDef *hdma) {
    if (hdma->Instance == DMA2_Channel6) {
        /* 复制 bufB 的数据 */
        uint16_t len = bufB_available ? UART_DMA_BUF_SIZE : 0;
        if (len > 0) {
            ProcessUartFrame(uartDmaBuf + UART_DMA_BUF_SIZE, len);
            bufB_available = 0;
        }
        bufA_available = 1;  /* bufA 即将有新数据 */
    }
}

/* 处理任务 —— 从 DMA 缓冲区中取出完整帧 */
void vUartProcessTask(void *pvParameters) {
    for (;;) {
        if (bufA_available) {
            ProcessUartFrame(uartDmaBuf, UART_DMA_BUF_SIZE);
            bufA_available = 0;
        }
        if (bufB_available) {
            ProcessUartFrame(uartDmaBuf + UART_DMA_BUF_SIZE, UART_DMA_BUF_SIZE);
            bufB_available = 0;
        }
        vTaskDelay(pdMS_TO_TICKS(10));
    }
}

/* 陷阱 1 的修复：确保 DMA 缓冲区 4 字节对齐 */

#include <stdint.h>

/* 方法 1：使用 GCC 属性 */
static uint8_t __attribute__((aligned(4))) uartDmaRxBuf[128];

/* 方法 2：使用 STM32 HAL 推荐的 ALIGNED 宏 */
static uint8_t __ALIGNED(4) adcDmaBuf[512];

/* 方法 3：在 struct 中确保字段对齐 */
typedef struct {
    uint16_t adc_value[256];  /* 256 × 2 = 512 字节，4 字节对齐自动满足 */
} AdcBuffer_t;

_Static_assert((sizeof(AdcBuffer_t) % 4) == 0, "DMA buffer must be 4-byte aligned");

/* 启动 DMA —— 此时地址一定是 4 字节对齐的 */
void AdcDmaStart(void) {
    HAL_ADC_Start_DMA(&hadc1, (uint32_t *)adcDmaBuf, 256);
    /* HAL 内部调用 HAL_DMA_Start_IT(&hdma_adc1, 
     *                              &hadc1.Instance->DR,
     *                              (uint32_t)adcDmaBuf,
     *                              256);
     * 如果 adcDmaBuf 未对齐，(uint32_t) 强制转换不会修正地址 */
}

/* 陷阱 2 的修复：编译期验证 size 是 2 的幂次 */
#define RING_BUF_SIZE  256
_Static_assert((RING_BUF_SIZE & (RING_BUF_SIZE - 1)) == 0,
               "Ring buffer size must be power of 2");

/* 使用位掩码替代取模 */
static inline uint16_t RingBuf_Index(uint16_t idx) {
    return idx & (RING_BUF_SIZE - 1);  /* 等价于 idx % RING_BUF_SIZE，但快 10 倍 */
}

// ========== 改进前：轮询 DMA 标志 ==========
// 问题：CPU 空转等待，DMA 标志清除逻辑和业务逻辑耦合

void ProcessUartData_Raw(void) {
    /* 启动 DMA 传输 */
    HAL_UART_Receive_DMA(&huart2, uartRxBuf, UART_BUF_SIZE);

    /* 忙等 DMA 传输完成 —— CPU 完全浪费在这里 */
    while (__HAL_DMA_GET_FLAG(&hdma_usart2_rx, DMA_FLAG_TC) == RESET) {
        /* 什么也不做，纯 CPU 浪费 */
    }

    /* DMA 完成后才处理数据 —— 此时 UART 可能已经收到了新数据 */
    uint16_t len = UART_BUF_SIZE - hdma_usart2_rx.Instance->NDTR;

    /* 清除 DMA 标志 —— 和业务逻辑混在一起 */
    __HAL_DMA_CLEAR_FLAG(&hdma_usart2_rx, DMA_FLAG_TC);

    /* 解析帧 —— 这段代码应该在不阻塞 CPU 的地方执行 */
    if (len > 0) {
        ParseAndProcess(uartRxBuf, len);
    }
}

