/* 环形缓冲区模块 —— 封装 DMA 操作 */
#define RING_BUF_SIZE  256
static uint8_t __ALIGNED(4) dmaRingBuf[RING_BUF_SIZE];
static volatile uint16_t dmaWriteIdx = 0;
static volatile uint16_t cpuReadIdx = 0;
static volatile uint8_t  bufReady = 0;

/* 环形缓冲区核心 API */
static uint16_t RingBuf_GetAvailable(void) {
    return dmaWriteIdx - cpuReadIdx;
}

static uint16_t RingBuf_Read(uint8_t *out, uint16_t maxLen) {
    uint16_t avail = RingBuf_GetAvailable();
    uint16_t toRead = (maxLen < avail) ? maxLen : avail;
    for (uint16_t i = 0; i < toRead; i++) {
        out[i] = dmaRingBuf[(cpuReadIdx + i) & (RING_BUF_SIZE - 1)];
    }
    cpuReadIdx += toRead;
    return toRead;
}

/* DMA 传输完成回调 —— 只有这个函数能修改 dmaWriteIdx */
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    if (huart->Instance == UART2) {
        /* DMA TC 触发：获取实际接收长度 */
        uint16_t transferred = RING_BUF_SIZE - hdma_usart2_rx.Instance->NDTR;

        /* 只更新 write_idx —— 这是唯一能修改它的地方 */
        dmaWriteIdx += transferred;

        /* 标记有数据可读 */
        bufReady = 1;
    }
}

/* 处理任务 —— 非阻塞地从缓冲区读取数据 */
void vUartProcessTask(void *pvParameters) {
    uint8_t frame[RING_BUF_SIZE];

    for (;;) {
        if (bufReady && RingBuf_GetAvailable() > 0) {
            uint16_t len = RingBuf_Read(frame, RING_BUF_SIZE);
            bufReady = 0;

            /* 处理完整帧 —— 不阻塞 DMA */
            ParseAndProcess(frame, len);
        }

        /* 让出 CPU 给其他任务 */
        vTaskDelay(pdMS_TO_TICKS(10));
    }
}
